import WebSocket from 'ws';
import * as readline from 'readline';

const ws = new WebSocket('ws://localhost:3000');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

ws.on('open', () => {
  console.log('Connected to chat server');
  rl.prompt();

  rl.on('line', (line) => {
    if (line.trim() === '') {
      rl.prompt();
      return;
    }
    ws.send(line);
    rl.prompt();
  });
});

ws.on('message', (data) => {
  const message = data.toString();
  console.log(`\nNew message: ${message}`);
  rl.prompt();
});

ws.on('close', () => {
  console.log('Disconnected from chat server');
  process.exit(0);
});

type IsString<T> = T extends string ? "Yes" : "No";

// Usage
type Test1 = IsString<string>; // "Yes"
type Test2 = IsString<number>; // "No"

interface NetworkError {
  type: "network";
  message: string;
  statusCode: number;
}

interface ValidationError {
  type: "validation";
  message: string;
  field: string;
}

// Conditional type to pick the shape based on error type

type AppError<T extends string> =
  T extends "network" ? NetworkError :
  T extends "validation" ? ValidationError :
  { type: "unknown"; message: string };

// Usage examples

const error1: AppError<"network"> = {
  type: "network",
  message: "Failed to connect",
  statusCode: 503,
};

const error2: AppError<"validation"> = {
  type: "validation",
  message: "Invalid email",
  field: "email",
};

type Result<T, E> = { success: true; value: T } | { success: false; error: E };

function fetchData(): Result<string, AppError<"network" | "validation">> {
  // Simulated error result
  return {
    success: false,
    error: {
      type: "network",
      message: "Timeout",
      statusCode: 504,
    },
  };
}

const result = fetchData();

if (!result.success) {
  // TypeScript will narrow the error type as one of NetworkError or ValidationError
  if (result.error.type === "network") {
    console.log("Network issue:", result.error.statusCode);
  } else if (result.error.type === "validation") {
    console.log("Validation error on field:", result.error.field);
  }
}

class DebugMeta(type):
    def __new__(cls, name, bases, attrs):
        print(f"Creating class {name} with DebugMeta")
        return super().__new__(cls, name, bases, attrs)

class MyClass(metaclass=DebugMeta):
    pass

class AutoAttrMeta(type):
    def __new__(cls, name, bases, attrs):
        attrs['custom_attr'] = f"This is added to {name}"  # Add a custom attribute
        return super().__new__(cls, name, bases, attrs)

class Example(metaclass=AutoAttrMeta):
    pass

print(Example.custom_attr)

class RegistryMeta(type):
    registry = {}

    def __new__(cls, name, bases, attrs):
        new_class = super().__new__(cls, name, bases, attrs)
        cls.registry[name] = new_class
        return new_class

class Base(metaclass=RegistryMeta):
    pass

class First(Base):
    pass

class Second(Base):
    pass

print(RegistryMeta.registry)

